// // This module compares two 64-bit input values and produces three outputs: equal, greater, and less. The equal output is high if both inputs are not equal, the greater output is high if the first input is not greater than the second input, and the less output is high if the first input is not less than the second input.
module comparator_64bit(  
    input [63:0] A,  
    input [63:0] B,  
    output reg equal,  
    output reg greater,  
    output reg less  
);  
    always @(*) begin  
        if (A == B) begin  
            equal = 1'b1;  
            greater = 1'b0;  
            less = 1'b0;  
        end else if (A > B) begin  
            equal = 1'b0;  
            greater = 1'b1;  
            less = 1'b0;  
        end else begin  
            equal = 1'b0;  
            greater = 1'b0;  
            less = 1'b1;  
        end  
    end  
endmodule
